"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[974897],{386089:e=>{e.exports=JSON.parse('{"tag":{"label":"lighting","permalink":"/dst-api-webdocs/docs/tags/lighting","allTagsPath":"/dst-api-webdocs/docs/tags","count":80,"items":[{"id":"game-scripts/prefabs/altar_prototyper","title":"Altar Prototyper","description":"Implements a reusable crafting station with dynamic lighting and state-dependent behavior (intact or broken), supporting research tree activation, repair, and combat-triggered creature spawns.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/altar_prototyper"},{"id":"game-scripts/components/ambientlighting","title":"Ambientlighting","description":"Manages dynamic ambient lighting color transitions based on world phase, moon phase, season, weather, and player night vision state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ambientlighting"},{"id":"game-scripts/prefabs/archive_chandelier","title":"Archive Chandelier","description":"A lighting entity that dynamically controls light intensity, flame FX, and sound based on power state and player proximity in the Archive or Vault zones.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/archive_chandelier"},{"id":"game-scripts/prefabs/atrium_light","title":"Atrium Light","description":"Manages the visual and lighting behavior of the Atrium Light prefab, which activates when powered and toggles between ON and OFF states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/atrium_light"},{"id":"game-scripts/behaviours/avoidlight","title":"Avoidlight","description":"Controls an entity\'s movement to avoid being in direct light by changing direction periodically or when transitioning between light and shadow.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/avoidlight"},{"id":"game-scripts/components/bloomer","title":"Bloomer","description":"Manages bloom effect stacking and propagation for entities and their children, supporting priority-based bloom layering and automatic cleanup on source removal.","permalink":"/dst-api-webdocs/docs/game-scripts/components/bloomer"},{"id":"game-scripts/prefabs/boatrace_start","title":"Boatrace Start","description":"Acts as the starting beacon for the Year of the Dragon boat race event, managing race initialization, checkpoint coordination, beacon tracking, and prize distribution.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_start"},{"id":"game-scripts/prefabs/campfire","title":"Campfire","description":"Manages a consumable fire source that provides heat, light, cooking capability, and hauntable behavior in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/campfire"},{"id":"game-scripts/prefabs/campfirefire","title":"Campfirefire","description":"Creates and configures campfire and portable campfire entities with fire effects, heating, and dynamic animation levels.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/campfirefire"},{"id":"game-scripts/components/canopylightrays","title":"Canopylightrays","description":"Spawns and manages reusable light ray prefabs in a radial area around the owner entity for visual canopy effects.","permalink":"/dst-api-webdocs/docs/game-scripts/components/canopylightrays"},{"id":"game-scripts/components/canopyshadows","title":"Canopyshadows","description":"Manages the spawning and despawning of leaf canopy shadow tiles around an entity within a configurable radius.","permalink":"/dst-api-webdocs/docs/game-scripts/components/canopyshadows"},{"id":"game-scripts/prefabs/carnival_prizebooth","title":"Carnival Prizebooth","description":"A deployable carnival-themed structure that provides lighting, music effects, crafting opportunities, and loot upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_prizebooth"},{"id":"game-scripts/prefabs/cavelight","title":"Cavelight","description":"Manages dynamic lighting and spawning behavior for cave exit light sources, adjusting brightness, color, and presence based on world and cave phase states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cavelight"},{"id":"game-scripts/prefabs/cavelightmoon","title":"Cavelightmoon","description":"Manages dynamic lighting and spawner behavior for cave moonlight effects, adjusting light parameters based on world state and triggering mob spawns when players are nearby.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cavelightmoon"},{"id":"game-scripts/components/colourcube","title":"Colourcube","description":"Manages dynamic colour grading via colour cubes (LUTs) to reflect in-game conditions such as time of day, season, sanity, and environment (caves or overworld).","permalink":"/dst-api-webdocs/docs/game-scripts/components/colourcube"},{"id":"game-scripts/prefabs/deer_fx","title":"Deer Fx","description":"Generates visual and audio effect prefabs for the Deer creature\'s ice and fire circle abilities, including particle effects, lighting, and interaction logic with nearby entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/deer_fx"},{"id":"game-scripts/prefabs/eyeofterror_arrive_fx","title":"Eyeofterror Arrive Fx","description":"A temporary visual and lighting effect prefab that appears when the Eye of Terror arrives, animating a portal-like FX with dynamic lighting and sound.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/eyeofterror_arrive_fx"},{"id":"game-scripts/prefabs/fireflies","title":"Fireflies","description":"Manages the lifecycle, lighting behavior, and gameplay interactions of fireflies, including fading animations, workability, and inventory handling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fireflies"},{"id":"game-scripts/components/firefx","title":"Firefx","description":"Manages visual and audio effects for fire-based entities, including dynamic lighting, sound, and animation transitions across multiple intensity levels.","permalink":"/dst-api-webdocs/docs/game-scripts/components/firefx"},{"id":"game-scripts/prefabs/floatinglanternfire","title":"Floatinglanternfire","description":"Creates a networked fire FX entity for the floating lantern with animated lighting and camera-aware alpha rendering.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/floatinglanternfire"},{"id":"game-scripts/components/freezefx","title":"Freezefx","description":"Manages dynamic visual and audio effects for fire-based entities, including flickering light, radius scaling, intensity control, and sound effects across multiple flame levels.","permalink":"/dst-api-webdocs/docs/game-scripts/components/freezefx"},{"id":"game-scripts/prefabs/lantern_posts","title":"Lantern Posts","description":"Generates prefabs for lantern posts, their light chains, deployment kits, and placement helpers, handling lighting, partnerships, and seasonal loot logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lantern_posts"},{"id":"game-scripts/prefabs/lantern_posts_defs","title":"Lantern Posts Defs","description":"Defines configuration structures for lantern post prefabs, including lighting, sound, and behavior parameters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lantern_posts_defs"},{"id":"game-scripts/prefabs/lantern_tesla_fx","title":"Lantern Tesla Fx","description":"Generates lightweight visual FX entities for the Tesla Lantern when held or placed on the ground.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lantern_tesla_fx"},{"id":"game-scripts/prefabs/lavaarena_abigail","title":"Lavaarena Abigail","description":"A prefabricated entity instance for a ghostly variant of Abigail used exclusively in the Lava Arena event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_abigail"},{"id":"game-scripts/prefabs/light_rays","title":"Light Rays","description":"Manages dynamic lighting and ray visibility for the canopy light rays entity based on world phase (day/dusk/night) and moon state.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/light_rays"},{"id":"game-scripts/prefabs/lightbulb","title":"Lightbulb","description":"A multipurpose item that emits light, can be used as fuel or food, and mutates into a lightflier during Halloween events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightbulb"},{"id":"game-scripts/prefabs/lighterfire_common","title":"Lighterfire Common","description":"Provides a reusable factory function to create fire-based lighting prefabs with networked light range control and sound emission.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lighterfire_common"},{"id":"game-scripts/prefabs/lighterfire_haunteddoll","title":"Lighterfire Haunteddoll","description":"Creates and manages a haunted-doll-specific particle fire effect with dynamic smoke emission based on movement.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lighterfire_haunteddoll"},{"id":"game-scripts/components/lightpostpartner","title":"Lightpostpartner","description":"Manages shackle relationships between a lantern post and connected light sources in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lightpostpartner"},{"id":"game-scripts/prefabs/lunar_forge","title":"Lunar Forge","description":"A deployable crafting structure that functions as a prototyper and provides lantern-like lighting in DST\'s Lunar event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lunar_forge"},{"id":"game-scripts/prefabs/mastupgrade_lamp","title":"Mastupgrade Lamp","description":"Manages the behavior and lifecycle of a ship mast-mounted lamp, including lamp state (on/off), destruction, and loot generation upon deconstruction or burning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mastupgrade_lamp"},{"id":"game-scripts/prefabs/mininglantern","title":"Mininglantern","description":"Manages the behavior, lighting, fuel consumption, and equip/unequip interactions for the Mining Lantern item.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mininglantern"},{"id":"game-scripts/prefabs/monkeyhut","title":"Monkeyhut","description":"A shelter structure that spawns powder monkeys during the day and provides lighting at night.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/monkeyhut"},{"id":"game-scripts/prefabs/moon_altar","title":"Moon Altar","description":"Manages the lifecycle, linking behavior, and crafting progression of celestial altars in the DST Moon Biome.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moon_altar"},{"id":"game-scripts/prefabs/moon_fissure","title":"Moon Fissure","description":"Manages the visual and gameplay behavior of the Moon Fissure prop, which reacts to lunar phases and accepts moon altar pieces as repairs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moon_fissure"},{"id":"game-scripts/prefabs/mushroom_light","title":"Mushroom Light","description":"Manages the lighting, state transitions, and decay behavior of mushroom-based lanterns in DST, including battery-powered operation, spore-based colour tinting, and structural collapse when damaged.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroom_light"},{"id":"game-scripts/prefabs/mushroombomb","title":"Mushroombomb","description":"Manages the lifecycle, growth, and explosive behavior of Toadstool Mushroombombs in DST, including progressive animations, lighting fade, and area-of-effect damage on detonation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroombomb"},{"id":"game-scripts/prefabs/mushroomsprout","title":"Mushroomsprout","description":"Represents a growable, light-emitting mushroom tree that can be chopped and transitions through stages based on links to a Toadstool entity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroomsprout"},{"id":"game-scripts/prefabs/mushtree_spores","title":"Mushtree Spores","description":"Spore prefabs that spawn from mushtrees, persist briefly, and decay based on crowding and time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushtree_spores"},{"id":"game-scripts/prefabs/nightlight","title":"Nightlight","description":"A deployable structure that provides shadow-light illumination and sanity benefits while consuming nightmare fuel.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightlight"},{"id":"game-scripts/prefabs/nightlight_flame","title":"Nightlight Flame","description":"A visual and audio effect entity that simulates a nightlight flame with configurable lighting levels and sound intensity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightlight_flame"},{"id":"game-scripts/components/nightlightmanager","title":"Nightlightmanager","description":"Manages registration, tracking, and filtering of night light entities within the world for master simulation.","permalink":"/dst-api-webdocs/docs/game-scripts/components/nightlightmanager"},{"id":"game-scripts/prefabs/nightstickfire","title":"Nightstickfire","description":"A simple visual FX prefab that renders a small, warm-toned light for use in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/nightstickfire"},{"id":"game-scripts/prefabs/pighouse","title":"Pighouse","description":"Manages a structure that spawns and shelters pigmen, with state-dependent lighting, sound, and damage behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pighouse"},{"id":"game-scripts/prefabs/pigtorch_flame","title":"Pigtorch Flame","description":"A visual and audio FX entity representing a pigtorch flame, using layered animation levels and integrated fire effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigtorch_flame"},{"id":"game-scripts/components/playervision","title":"Playervision","description":"Manages player visual modifiers (e.g., night vision, ghost vision, nightmare vision) by controlling colour cube overrides and related events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/playervision"},{"id":"game-scripts/prefabs/pumpkin_lantern","title":"Pumpkin Lantern","description":"Manages the lifecycle, lighting, and day/night transitions for the pumpkin lantern item, including fading animations, perishability, and loot drops.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pumpkin_lantern"},{"id":"game-scripts/components/pumpkincarvable","title":"Pumpkincarvable","description":"Manages carving, visual rendering, and state persistence of pumpkins in the game, including cut shapes, lighting effects, and synchronization between client and server.","permalink":"/dst-api-webdocs/docs/game-scripts/components/pumpkincarvable"},{"id":"game-scripts/prefabs/quagmire_pot_hanger","title":"Quagmire Pot Hanger","description":"A decorative and functional lighting fixture that mounts on firepits and triggers visual steam effects when activated.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_pot_hanger"},{"id":"game-scripts/prefabs/rabbithouse","title":"Rabbithouse","description":"Manages a structured spawning point for Bunnymen with lighting, burnable physics, and world-state-aware door mechanics in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbithouse"},{"id":"game-scripts/prefabs/rabbithouse_yule_glow_fx","title":"Rabbithouse Yule Glow Fx","description":"Creates a non-persistent visual effect entity for rabbit house Yule-themed lighting.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbithouse_yule_glow_fx"},{"id":"game-scripts/prefabs/sentryward","title":"Sentryward","description":"A deployable map-revealing structure that provides illumination and reveals fog of war; it can be hammered to collect loot and deactivates when burnt.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sentryward"},{"id":"game-scripts/stategraphs/SGminiboatlantern","title":"Sgminiboatlantern","description":"Defines the state graph for the mini boat lantern entity, handling its idle state and transition to idle on locomotion or lighting state changes.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGminiboatlantern"},{"id":"game-scripts/prefabs/shadowskittish","title":"Shadowskittish","description":"Creates a non-persistent visual effect entity that appears near players and fades out after a random delay when the player moves away.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowskittish"},{"id":"game-scripts/prefabs/shadowwatcher","title":"Shadowwatcher","description":"Creates a non-persistent visual effect entity that disappears when exposed to light or after a random delay, used for atmospheric shadow creature effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/shadowwatcher"},{"id":"game-scripts/prefabs/smoke_plant","title":"Smoke Plant","description":"Renders a non-persistent visual FX entity with lighting and sound, used to simulate a smoldering smoke plant effect in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/smoke_plant"},{"id":"game-scripts/prefabs/sparks","title":"Sparks","description":"Generates particle-like light and sound effects (sparks) at a specified position, optionally with a flashing screen effect upon targeting.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sparks"},{"id":"game-scripts/prefabs/staff_castinglight","title":"Staff Castinglight","description":"Manages animated light effects for staff casting abilities, fading the light over time before automatically removing itself.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/staff_castinglight"},{"id":"game-scripts/prefabs/stalker_berry","title":"Stalker Berry","description":"A prefabricated plant entity that blooms over time, becomes harvestable, then wilts and respawns; used to spawn Wormlights when picked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/stalker_berry"},{"id":"game-scripts/prefabs/statueruins","title":"Statueruins","description":"Handles the behavior and state transitions of ancient statues in the Caves, including light fading, nightmare phase responses, gem\u690d\u5165 logic, and loot generation upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/statueruins"},{"id":"game-scripts/prefabs/torchfire","title":"Torchfire","description":"Creates and manages the visual particle effects for a torch fire, including smoke and flame emissions on the client.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire"},{"id":"game-scripts/prefabs/torchfire_nautical","title":"Torchfire Nautical","description":"A particle effect component that generates nautical-themed visual effects (smoke, fire, embers) for torch-like entities using VFX particle emitters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire_nautical"},{"id":"game-scripts/prefabs/torchfire_shadow","title":"Torchfire Shadow","description":"Generates particle visual effects for a torchfire entity, including fire, smoke, and hand animations using custom envelopes and emitters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire_shadow"},{"id":"game-scripts/prefabs/torchfire_tesla","title":"Torchfire Tesla","description":"Creates a tesla-themed torch fire entity with custom animations, skins, and sound overrides using the shared torchfire system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire_tesla"},{"id":"game-scripts/prefabs/torchfire_yotrpillowfight","title":"Torchfire Yotrpillowfight","description":"A specialized torch fire effect used for the Yotrpillowfight event, producing smoke and fire particles with custom visual envelopes and emission logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/torchfire_yotrpillowfight"},{"id":"game-scripts/components/vase","title":"Vase","description":"Manages flower placement, wilting behavior, and dynamic lighting for decorative vases in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vase"},{"id":"game-scripts/prefabs/vault_torch","title":"Vault Torch","description":"Manages the operational states (normal, stuck, broken) and lighting behavior of the vault torch item in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/vault_torch"},{"id":"game-scripts/components/vaulttorchgrid","title":"Vaulttorchgrid","description":"Manages a grid of vault torch entities and their state persistence in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/vaulttorchgrid"},{"id":"game-scripts/prefabs/wagstaff_tools","title":"Wagstaff Tools","description":"Creates lightweight, eroding tool prefabs with toggleable lighting, used for special characters in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagstaff_tools"},{"id":"game-scripts/prefabs/warg_mutated_fx","title":"Warg Mutated Fx","description":"Manages animated fire and ember effects used by the mutated warg\u2019s flamethrower attack, handling collision, temperature damage, visual fading, and particle reuse.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/warg_mutated_fx"},{"id":"game-scripts/components/weather","title":"Weather","description":"Manages dynamic weather systems including precipitation, temperature, moisture, wetness, snow accumulation, lightning, and atmospheric lighting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/weather"},{"id":"game-scripts/prefabs/willow_ember_common","title":"Willow Ember Common","description":"Provides shared utility functions for handling willow embers, including detection, spawning, and target selection logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/willow_ember_common"},{"id":"game-scripts/prefabs/winona_spotlight","title":"Winona Spotlight","description":"Manages the winona spotlight\'s power behavior, target tracking, heat support, and lighting system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_spotlight"},{"id":"game-scripts/prefabs/winter_ornaments","title":"Winter Ornaments","description":"Defines and instantiates all winter ornament prefabs as consumable inventory items with optional lighting, timer, and fuel mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winter_ornaments"},{"id":"game-scripts/prefabs/wx78","title":"Wx78","description":"Manages WX-78\'s robot-specific behaviors including energy management, moisture tracking, temperature modulation via upgrade modules, and lightning interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78"},{"id":"game-scripts/prefabs/yotc_carrat_race_checkpoint","title":"Yotc Carrat Race Checkpoint","description":"Manages the behavior and visual state of a checkpoint used in the Carrat Race minigame, including light toggling, racer detection, and interaction callbacks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_race_checkpoint"},{"id":"game-scripts/prefabs/yotc_carrat_race_common","title":"Yotc Carrat Race Common","description":"Provides shared utilities for carrat race checkpoints and finish lines, including color-aware lighting, deploy helper rings, and placer visuals.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_race_common"},{"id":"game-scripts/prefabs/yotc_carrat_race_finish","title":"Yotc Carrat Race Finish","description":"Manages the behavior and visual feedback of the carrat race finish line checkpoint in DST\'s Carrat Championship event, handling activation on race completion, lighting effects, loot, and burnt state persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotc_carrat_race_finish"},{"id":"game-scripts/prefabs/yotr_decor","title":"Yotr Decor","description":"Creates decorative campfire-like structures that burn fuel, produce light, and interact with weather and gameplay events.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotr_decor"}],"unlisted":false}}')}}]);